const Redis = require('ioredis');

const patientId = $input.first().json.query?.patientId || $input.first().json.body?.patientId;

if (!patientId) {
  return [{ json: { success: false, error: 'patientId required' } }];
}

const redis = new Redis({ host: 'redis', port: 6379 });

try {
  const patient = await redis.hgetall(`patient:${patientId}`);
  if (!patient || !patient.name) {
    await redis.quit();
    return [{ json: { success: false, error: 'Patient not found' } }];
  }

  if (patient.deviceId) {
    await redis.del(`device:${patient.deviceId}`);
  }

  const contactIds = await redis.lrange(`patient:${patientId}:contacts`, 0, -1);
  for (const id of contactIds) {
    await redis.del(`contact:${id}`);
  }
  await redis.del(`patient:${patientId}:contacts`);

  const photoIds = await redis.lrange(`patient:${patientId}:photos`, 0, -1);
  for (const id of photoIds) {
    await redis.del(`photo:${id}`);
  }
  await redis.del(`patient:${patientId}:photos`);

  await redis.del(`patient:${patientId}`);
  await redis.srem('patients', patientId);

  await redis.quit();
  return [{ json: { success: true, deletedPatientId: patientId } }];
} catch (err) {
  await redis.quit().catch(() => {});
  throw err;
}
